VALUES
  ('heelevel3-5ff21eeb-moex-00154', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '納稅者權利保護法有關稅捐稽徵機關之規定，下列敘述何者錯誤？', '["稅捐稽徵機關就欠繳應納稅捐之個人為限制出境處分前，應給予陳述意見之機會", "稅捐稽徵機關對於通知調查將無法達成稽徵或調查目的之案件，免於通知調查前通知被調查者", "稅捐稽徵機關得為維持稅捐調查秘密性之正當理由，拒絕被調查者關於錄影、錄音之要求", "稅捐稽徵機關違法調查所取得之證據，其違法取得證據之情節輕微，排除該證據之使用明顯有 違公共利益者，該證據仍得作為認定課稅或處罰之基礎"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00155', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', 'A公司欲為其欠繳之營業稅提供相當擔保，下列關於擔保品之敘述何者錯誤？', '["提供黃金作為擔保品者，鑑定所需之費用，由納稅義務人負擔", "提供土地作為擔保品且無時價資料者，按公告地價加2成估算", "提供銀行定期存單作為擔保品者，按本金額計值", "提供房屋作為擔保品且無時價資料者，按稅捐稽徵機關核計之房屋現值加2成估算"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00156', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '關於未設管理人之公同共有財產稅捐之核課，下列敘述何者錯誤？', '["以全體公同共有人為納稅義務人", "各公同共有人對應納稅捐負連帶責任", "稅捐稽徵機關應繕發核定稅額通知書送達全體公同共有人", "繳款書向公同共有人其中一人送達，效力及於全體"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00157', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '貨物稅產製廠商就當月份出廠貨物之應納稅款，依貨物稅條例第23條第1項規定，於次月15日以前 向主管稽徵機關申報，嗣經主管稽徵機關以公告方式，載明按申報資料核定，代替核定稅額通知 書之填具及送達，下列敘述何者正確？', '["核定稅額通知書既經公告送達，產製廠商不得再申請補發", "經公告核定且未於規定期限申請復查即發生確定效力，主管稽徵機關不得再補稅處罰", "不服該公告核定案件，自公告日起30日內申請復查", "自公告日發生按產製廠商申報資料核定效力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00158', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', 'A營業人逾法定申報期限5日始申報當年1-2月期營業稅，且無故意以詐欺或其他不正當方法逃漏 稅捐，請問該期營業稅之核課期間為幾年？自何時起算？', '["5年、自A營業人當年1-2月期營業稅申報日起算", "5年、自A營業人當年1-2月期營業稅法定申報期間屆滿之次日起算", "7年、自A營業人當年1-2月期營業稅申報日起算", "7年、自A營業人當年1-2月期營業稅法定申報期間屆滿之次日起算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00159', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '納稅義務人對核定稅捐處分不服提起行政救濟，該稅捐處分核課期間於本年7月31日屆滿時仍繫 屬最高行政法院，嗣經最高行政法院判決撤銷核定稅捐處分須另為處分並於同年10月20日確定， 下列關於本案核課期間時效不完成，何者正確？', '["本案核課期間，自本年7月31日起算1年內，時效不完成", "本案核課期間，自本年8月1日起算1年內，時效不完成", "本案核課期間，自本年10月20日起算1年內，時效不完成", "本案核課期間，自本年10月21日起算1年內，時效不完成"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00160', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '稅捐稽徵機關對於有隱匿或移轉財產、逃避稅捐執行跡象之納稅義務人，聲請法院對其財產實施 假扣押，下列敘述何者錯誤？', '["得於繳納通知文書送達前，向法院聲請假扣押", "屬已依法申報而未繳納稅捐者，得於法定繳納期間屆滿後向法院聲請假扣押", "稅捐稽徵機關聲請假扣押免提供擔保", "納稅義務人於實施假扣押後提供相當擔保，應解除假扣押"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00161', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '納稅義務人因欠繳稅捐經財政部函請內政部移民署為限制出境處分者，下列何者非解除出境限制 之事由？', '["自內政部移民署限制出境日起算，已逾5年", "納稅義務人繳清全部欠稅款", "欠稅款業依破產法規定之破產程序分配完結，但未獲全額清償", "行政救濟程序終結，確定欠稅及罰鍰總計新臺幣（下同）500萬元，未繳清亦未提供擔保"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00162', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '關於稅捐稽徵法之適用範圍，下列敘述何者錯誤？', '["關稅不適用稅捐稽徵法", "進口貨物營業稅之復查，準用關稅法及海關緝私條例之規定辦理", "地方稅法通則未規定者，依稅捐稽徵法及其他有關法律之規定", "逾期繳納稅捐應否加徵滯納利息，應依稅捐稽徵法之規定辦理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00163', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-112-4245dbf9', 'sub-heelevel3-5ff21eeb-05', NULL, 'single_choice', '國稅局核定甲納稅義務人應補繳綜合所得稅，繳款書記載繳納期間為112年8月1日至同年8月10 日，繳款書於同年7月27日送達，甲君不服該核定稅捐處分，請問甲君申請復查期間為何（不考慮 納稅義務人因天災、事變或其他不可抗力事由致遲誤申請復查，以及期間末日為星期例假日、國 定假日或其他政府機關不上班日之情形）？', '["自112年7月28日起算30日", "自112年8月1日起算30日", "自112年8月10日起算30日", "自112年8月11日起算30日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:07+00:00", "source_pdf_sha1": "3d017b511096", "answer_pdf_sha1": "4972a3dcd965", "source_family": "moex-gov-tw", "moex": {"exam_code": "112090", "c": "325", "s": "1005", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "納稅者權利保護法及稅捐稽徵法", "year": "112", "exam_name": "112年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL)
